This simulation visualizes Newton's First Law by modeling particles moving in a near-vacuum environment, where the primary influence is maintaining their initial momentum. By setting gravity, damping, and friction to near zero, the particles will continue to coast in a straight line unless an external force (like an added wind or collision) acts upon them.

```json
{
  "simulation": {
    "prompt": "Illustrating Newton's First Law of Inertia through coasting particles.",
    "title": "Inertia Demonstration (Law of Inertia)",
    "description": "Particles continue moving at a constant velocity in the absence of net external forces.",
    "domain": "physics",
    "physics": {
      "gravity": 0.0,
      "damping": 0.99,
      "springStiffness": 20,
      "particleCount": 15000,
      "timeScale": 1.0,
      "friction": 0.1,
      "bounciness": 0.2,
      "windX": 0, "windY": 0, "windZ": 0,
      "turbulence": 0,
      "viscosity": 0,
      "temperature": 293
    },
    "particles": {
      "groups": [
        {
          "name": "Group A (Moving)",
          "count": 7000,
          "shape": "sphere",
          "params": {
            "initialVelocity": [5, 0, 0]
          },
          "color": "blue",
          "role": 1,
          "connect": "none"
        },
        {
          "name": "Group B (Stationary)",
          "count": 8000,
          "shape": "sphere",
          "params": {
            "initialVelocity": [0, 0, 0]
          },
          "color": "cyan",
          "role": 0,
          "connect": "none"
        }
      ]
    }
  }
}
```

